// Read sync cursor from postgres so we know the last successful sync time.
// Output the cursor + workspace metadata for downstream nodes.
const pgItems = $('Read sync state').all();
const cursors = {};
for (const it of pgItems) {
  cursors[it.json.entity] = it.json.cursor || null;
}

// First-run backfill window — read from a workflow variable if set, else default 30 days
const backfillDays = parseInt($env.SLACK_BACKFILL_DAYS || '30', 10);
const now = Math.floor(Date.now() / 1000);
const defaultOldest = now - (backfillDays * 86400);

return [{
  json: {
    cursors,
    now,
    default_oldest: defaultOldest,
    backfill_days: backfillDays
  }
}];

// Upsert channels and users into postgres. We do it in JS so we can build
// parameterized SQL safely (Slack channel names/users may contain quotes).
const channels = ($json.channels || []).filter(c => !c.is_im && !c.is_mpim);
const out = [];
for (const c of channels) {
  out.push({
    json: {
      id: c.id,
      name: c.name || '(unnamed)',
      is_archived: !!c.is_archived,
      is_private: !!c.is_private,
      is_im: !!c.is_im,
      is_mpim: !!c.is_mpim,
      num_members: c.num_members || 0,
      purpose: (c.purpose && c.purpose.value) || null,
      topic: (c.topic && c.topic.value) || null,
      created_unix: c.created || null
    }
  });
}
return out;

const users = ($json.members || []);
const out = [];
for (const u of users) {
  const p = u.profile || {};
  out.push({
    json: {
      id: u.id,
      name: u.name || null,
      real_name: u.real_name || p.real_name || null,
      display_name: p.display_name || null,
      email: p.email || null,
      is_bot: !!u.is_bot,
      is_admin: !!u.is_admin,
      is_deleted: !!u.deleted,
      tz: u.tz || null
    }
  });
}
return out;

// Build a list of {channel_id, oldest_ts} pairs to fetch messages for.
// For each non-archived public/private channel, we'll fetch its messages.
//
// The cursor for messages is per-channel: last successfully-fetched ts.
// For v1 we use a single global cursor in _meta.sync_state to keep things
// simple; per-channel cursors are a v2 refinement.
const channels = $('Format channels').all().map(i => i.json).filter(c => !c.is_archived);
const computeOutput = $('Compute window').first().json;
const cursor = (computeOutput.cursors && computeOutput.cursors.messages) || null;
const oldest = cursor || computeOutput.default_oldest;

const out = [];
for (const c of channels) {
  out.push({
    json: {
      channel_id: c.id,
      channel_name: c.name,
      oldest: oldest,
      latest: computeOutput.now
    }
  });
}
return out;

// Flatten conversations.history response into per-message rows.
// Note: $json here is one channel's response; messages is an array.
const channel_id = $('Plan message fetches').item.json.channel_id;
const messages = $json.messages || [];
const out = [];
for (const m of messages) {
  // Skip bot status / system messages we don't care about for digests
  if (m.subtype && ['channel_join','channel_leave','channel_topic','channel_purpose'].includes(m.subtype)) {
    continue;
  }
  out.push({
    json: {
      ts: m.ts,
      channel_id,
      user_id: m.user || (m.bot_id ? null : null),
      text: m.text || '',
      thread_ts: m.thread_ts || null,
      reply_count: m.reply_count || 0,
      reactions: m.reactions ? JSON.stringify(m.reactions) : null,
      files: m.files ? JSON.stringify(m.files) : null,
      message_type: m.type || 'message',
      subtype: m.subtype || null,
      edited_ts: (m.edited && m.edited.ts) || null
    }
  });
}
return out;
